# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import Foundation

struct User {
    let id: Int
    let name: String
}

class NetworkingService {
    private let baseURL = "https://api.example.com"
    
    func fetchUserData(completion: @escaping ([User]) -> ()) {
        let url = URL(string: "\(baseURL)/users")!
        
        // Create a URLRequest to GET the user data
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        // Use URLSession to send the request and retrieve the response
        let task = URLSession.shared.dataTask(with: request) { (data, response, error) in
            if let error = error {
                print("Error fetching user data: \(error)")
                return
            }
            
            // Parse the JSON response and create an array of User objects
            guard let jsonData = data else {
                print("No data returned from API")
                return
            }
            do {
                let decoder = JSONDecoder()
                let users = try decoder.decode([User].self, from: jsonData)
                completion(users)
            } catch {
                print("Error parsing JSON response: \(error)")
            }
        }
        
        task.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Bool) -> ()) {
        let url = URL(string: "\(baseURL)/users/authenticate")!
        
        // Create a URLRequest to POST the user credentials
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let jsonData = try! JSONEncoder().encode(["username": username, "password": password])
        request.httpBody = jsonData
        
        // Use URLSession to send the request and retrieve the response
        let task = URLSession.shared.dataTask(with: request) { (data, response, error) in
            if let error = error {
                print("Error authenticating user: \(error)")
                return
            }
            
            // Parse the JSON response and check for a successful authentication
            guard let jsonData = data else {
                print("No data returned from API")
                return
            }
            do {
                let decoder = JSONDecoder()
                let authenticated = try decoder.decode(Bool.self, from: jsonData)
                completion(authenticated)
            } catch {
                print("Error parsing JSON response: \(error)")
            }
        }
        
        task.resume()
    }
}